import {
  BoxGeometry,
  Color,
  DoubleSide,
  Group,
  InstancedMesh,
  Matrix4,
  MeshBasicMaterial,
  PlaneGeometry,
  Vector3,
  MeshStandardMaterial,
} from "three";

import { MINECRAFT_PALETTE } from "./visual-modes/minecraft/palette";

/**
 * True voxel world for the Minecraft mode: the city as axis-aligned
 * blocks generated by `isometric_berlin.generation.build_minecraft_voxels`
 * from surveyed LoD2 footprints + measured heights, OSM water/roads and
 * the official tree points. Rendered as a handful of InstancedMeshes
 * (one box per building column / ground run / tree part) so the whole
 * world stays at a few draw calls and well below photogrammetry-tier
 * triangle counts — deliberately "eckig, klotzig, blockig".
 */
export type VoxelPayload = {
  schema_version: number;
  cell_m: number;
  classes: string[];
  grid: { cols: number; min_x_idx: number; min_z_idx: number; rows: number };
  /** Coarse ground-top heights in decimetres, row-major at stride_cells. */
  ground_height: {
    cols: number;
    rows: number;
    stride_cells: number;
    y_dm: number[];
  };
  /** rows[z_offset] = [x_start_offset, run_length, classId][] (grid offsets). */
  ground_rows: Array<Array<[number, number, number]>>;
  /** [x_idx, z_idx, y0_dm, y1_dm, classId] with ABSOLUTE cell indices. */
  buildings: Array<[number, number, number, number, number]>;
  /** [x_idx, z_idx, y0_dm, height_dm] with ABSOLUTE cell indices. */
  trees: Array<[number, number, number, number]>;
  water_top_y_m: number;
};

export const VOXEL_WORLD_FILE = "minecraft-voxels.json";
const GROUND_SLAB_M = 3;
const WATER_TOP_Y = 1.31;

// Every shade comes from MINECRAFT_PALETTE (palette.ts); small
// deterministic per-instance jitter between shades is what gives the
// classic Minecraft block-noise without any texture.
// Owner note "bessere Farben im Minecraft mode": each class now uses
// two or three CLOSE shades (gentle block-noise instead of the harsh
// checkerboard), greens follow classic plains grass/oak leaves, water is
// the clear Minecraft blue and roads read as dark slate, not void-black.
const CLASS_SHADES: Record<string, readonly number[]> = {
  asphalt: [0x40515c, 0x34443a],
  concrete: [0xd4d4b7, 0xf3efd0],
  glass: [0x72c5d2, 0xa4dfe2],
  grass: [0x74b043, 0x5d9634, 0x74b043],
  plazaBrick: [0x994a35, 0x715b4a],
  // Bridge decks over the Spree/Humboldthafen read as stone blocks.
  bridge: [0x8e9a9e, 0xa4aa91],
  sandstone: [0xe8d1ae, 0xf5e3c5],
  water: [0x3f76e4, 0x2e5aa8],
};
const FALLBACK_SHADES: readonly number[] = CLASS_SHADES.concrete;
const TRUNK_SHADES: readonly number[] = [0x704a2d];
const LEAF_SHADES: readonly number[] = [0x4c7f28, 0x5d9634];
// Facade window cells on exterior column faces: mostly dark stone-glass
// with an occasional teal pane, both from the master palette.
const VOXEL_WINDOW_DARK = 0x40515c;
const VOXEL_WINDOW_TEAL = 0x72c5d2;

function shadeFor(
  shades: readonly number[],
  xIdx: number,
  zIdx: number,
  salt: number,
): Color {
  const pick = Math.abs(xIdx * 31 + zIdx * 17 + salt * 7) % shades.length;
  return new Color(shades[pick]);
}

function voxelMaterial(): MeshStandardMaterial {
  return new MeshStandardMaterial({
    color: 0xffffff,
    // A small neutral emissive floor lifts the shadow faces so block
    // colours stay readable all around, like Minecraft's flat light.
    emissive: 0x2c2c2c,
    flatShading: true,
    metalness: 0,
    roughness: 1,
  });
}

type InstanceWriter = {
  mesh: InstancedMesh;
  write: (
    center: Vector3,
    size: Vector3,
    color: Color,
  ) => void;
};

function instancedBoxes(name: string, count: number): InstanceWriter {
  const mesh = new InstancedMesh(
    new BoxGeometry(1, 1, 1),
    voxelMaterial(),
    Math.max(1, count),
  );
  mesh.name = name;
  mesh.count = 0;
  const matrix = new Matrix4();
  return {
    mesh,
    write: (center, size, color) => {
      const index = mesh.count;
      matrix.makeScale(size.x, size.y, size.z);
      matrix.setPosition(center.x, center.y, center.z);
      mesh.setMatrixAt(index, matrix);
      mesh.setColorAt(index, color);
      mesh.count = index + 1;
    },
  };
}

/**
 * Sample the payload's coarse interpolated terrain grid at grid offsets.
 */
export function groundTopSampler(
  payload: VoxelPayload,
): (xOffset: number, zOffset: number) => number {
  const heights = payload.ground_height;
  return (xOffset, zOffset) => {
    const col = Math.min(
      heights.cols - 1,
      Math.floor(xOffset / heights.stride_cells),
    );
    const row = Math.min(
      heights.rows - 1,
      Math.floor(zOffset / heights.stride_cells),
    );
    return (heights.y_dm[row * heights.cols + col] ?? 40) / 10;
  };
}

/**
 * Per-column real-colour lookup: point-in-footprint against the LoD2
 * prism payload, each building's sampled tone snapped to the nearest
 * Minecraft palette entry. Kills the one-colour-city ("einfarbig")
 * while staying strictly inside the authored block palette.
 */
export type ColumnToneLookup = (x: number, z: number) => number | null;

type TonedPrism = {
  hex: number;
  maxX: number;
  maxZ: number;
  minX: number;
  minZ: number;
  ring: Array<[number, number]>;
};

export function buildColumnToneLookup(prisms: {
  buildings: Array<{ ring: number[][]; tone?: [number, number, number] }>;
}): ColumnToneLookup {
  const palette = MINECRAFT_PALETTE.map((hex) => ({
    b: hex & 255,
    g: (hex >> 8) & 255,
    hex,
    r: (hex >> 16) & 255,
  }));
  const snap = (tone: [number, number, number]): number => {
    let best = palette[0].hex;
    let bestDistance = Number.POSITIVE_INFINITY;
    for (const entry of palette) {
      const distance =
        (tone[0] - entry.r) ** 2 +
        (tone[1] - entry.g) ** 2 +
        (tone[2] - entry.b) ** 2;
      if (distance < bestDistance) {
        bestDistance = distance;
        best = entry.hex;
      }
    }
    return best;
  };
  const BUCKET = 32;
  const buckets = new Map<string, TonedPrism[]>();
  for (const building of prisms.buildings) {
    if (!building.tone || building.ring.length < 3) {
      continue;
    }
    const ring = building.ring.map(
      ([x, z]) => [x / 10, z / 10] as [number, number],
    );
    const xs = ring.map(([x]) => x);
    const zs = ring.map(([, z]) => z);
    const toned: TonedPrism = {
      hex: snap(building.tone),
      maxX: Math.max(...xs),
      maxZ: Math.max(...zs),
      minX: Math.min(...xs),
      minZ: Math.min(...zs),
      ring,
    };
    for (
      let bx = Math.floor(toned.minX / BUCKET);
      bx <= Math.floor(toned.maxX / BUCKET);
      bx += 1
    ) {
      for (
        let bz = Math.floor(toned.minZ / BUCKET);
        bz <= Math.floor(toned.maxZ / BUCKET);
        bz += 1
      ) {
        const key = `${bx},${bz}`;
        const list = buckets.get(key);
        if (list) {
          list.push(toned);
        } else {
          buckets.set(key, [toned]);
        }
      }
    }
  }
  const inside = (x: number, z: number, ring: Array<[number, number]>): boolean => {
    let odd = false;
    for (let i = 0, j = ring.length - 1; i < ring.length; j = i, i += 1) {
      const [xi, zi] = ring[i];
      const [xj, zj] = ring[j];
      if (zi > z !== zj > z && x < ((xj - xi) * (z - zi)) / (zj - zi) + xi) {
        odd = !odd;
      }
    }
    return odd;
  };
  return (x, z) => {
    const list = buckets.get(`${Math.floor(x / BUCKET)},${Math.floor(z / BUCKET)}`);
    if (!list) {
      return null;
    }
    for (const toned of list) {
      if (
        x >= toned.minX && x <= toned.maxX &&
        z >= toned.minZ && z <= toned.maxZ &&
        inside(x, z, toned.ring)
      ) {
        return toned.hex;
      }
    }
    return null;
  };
}

/**
 * World-coordinate ground sampler: metres in, terrain-top metres out,
 * null outside the surveyed grid.
 */
export function worldGroundSampler(
  payload: VoxelPayload,
): (x: number, z: number) => number | null {
  const sample = groundTopSampler(payload);
  const cell = payload.cell_m;
  const { cols, min_x_idx, min_z_idx, rows } = payload.grid;
  return (x, z) => {
    const xOffset = x / cell - min_x_idx;
    const zOffset = z / cell - min_z_idx;
    if (xOffset < 0 || zOffset < 0 || xOffset >= cols || zOffset >= rows) {
      return null;
    }
    return sample(xOffset, zOffset);
  };
}

/**
 * Build the run-length ground slabs as one InstancedMesh. Shared between
 * the Minecraft voxel world and the drawn isometric city (which reuses
 * the same surveyed ground/water/road classes with its own palette).
 */
export function createGroundSlabs(
  payload: VoxelPayload,
  name: string,
  shadeMap: Record<string, readonly number[]>,
): InstancedMesh {
  const cell = payload.cell_m;
  const { min_x_idx, min_z_idx } = payload.grid;
  const worldXAbs = (xIdx: number, span = 1): number =>
    (xIdx + span / 2) * cell;
  const worldZAbs = (zIdx: number): number => (zIdx + 0.5) * cell;
  const groundTopY = groundTopSampler(payload);
  const groundRunCount = payload.ground_rows.reduce(
    (sum, row) => sum + row.length,
    0,
  );
  const ground = instancedBoxes(name, groundRunCount);
  const center = new Vector3();
  const size = new Vector3();
  payload.ground_rows.forEach((row, zOffset) => {
    for (const [xStart, run, classId] of row) {
      const className = payload.classes[classId] ?? "grass";
      const shades =
        shadeMap[className] ?? shadeMap.grass ?? FALLBACK_SHADES;
      const topY =
        className === "water"
          ? (payload.water_top_y_m ?? WATER_TOP_Y)
          : groundTopY(xStart + run / 2, zOffset);
      center.set(
        worldXAbs(min_x_idx + xStart, run),
        topY - GROUND_SLAB_M / 2,
        worldZAbs(min_z_idx + zOffset),
      );
      size.set(run * cell, GROUND_SLAB_M, cell);
      ground.write(center, size, shadeFor(shades, xStart, zOffset, run));
    }
  });
  return ground.mesh;
}

export function createMinecraftVoxelWorld(
  payload: VoxelPayload,
  toneLookup?: ColumnToneLookup | null,
): Group {
  const group = new Group();
  group.name = "Minecraft voxel world (LoD2 + OSM + official tree points)";
  const cell = payload.cell_m;
  // Buildings/trees carry ABSOLUTE cell indices; ground runs are grid
  // offsets (see the payload origin note): cell (x_idx, z_idx) spans
  // world x in [x_idx*cell, x_idx*cell + cell).
  const worldXAbs = (xIdx: number, span = 1): number =>
    (xIdx + span / 2) * cell;
  const worldZAbs = (zIdx: number): number => (zIdx + 0.5) * cell;
  const center = new Vector3();
  const size = new Vector3();
  group.add(createGroundSlabs(payload, "Voxel ground runs", CLASS_SHADES));

  const buildings = instancedBoxes(
    "Voxel building columns",
    payload.buildings.length * 2,
  );
  const tonePaint = new Color();
  for (const [xIdx, zIdx, y0dm, y1dm, classId] of payload.buildings) {
    const className = payload.classes[classId] ?? "concrete";
    const shades = CLASS_SHADES[className] ?? FALLBACK_SHADES;
    const y0 = y0dm / 10;
    const height = Math.max(cell, (y1dm - y0dm) / 10);
    // Real building colour when the prism payload knows this footprint;
    // whole buildings read as one hue (no checkerboard), the class
    // shades stay as fallback for unknown columns.
    const tone = toneLookup?.(worldXAbs(xIdx), worldZAbs(zIdx)) ?? null;
    const facade =
      tone !== null
        ? tonePaint.setHex(tone).clone()
        : shadeFor(shades, xIdx, zIdx, Math.round(height / cell));
    // Minecraft buildings wear a darker roof layer — the top block row
    // reads as roofing, like the game's slab-capped houses.
    const capHeight = height > 3 ? 1 : 0;
    center.set(worldXAbs(xIdx), y0 + (height - capHeight) / 2, worldZAbs(zIdx));
    size.set(cell, height - capHeight, cell);
    buildings.write(center, size, facade);
    if (capHeight > 0) {
      center.set(worldXAbs(xIdx), y0 + height - capHeight / 2, worldZAbs(zIdx));
      size.set(cell, capHeight, cell);
      buildings.write(center, size, facade.clone().multiplyScalar(0.72));
    }
  }
  group.add(buildings.mesh);

  // Window cells on exterior faces: every ~4 m storey of a column face
  // that no neighbouring column covers gets a recessed dark pane —
  // blocky fenestration, strictly from the surveyed columns.
  const columnTops = new Map<number, number>();
  const columnKey = (x: number, z: number): number => x * 65536 + z;
  for (const [xIdx, zIdx, , y1dm] of payload.buildings) {
    const key = columnKey(xIdx, zIdx);
    columnTops.set(key, Math.max(columnTops.get(key) ?? -1e9, y1dm / 10));
  }
  type WindowFace = { color: Color; nx: number; nz: number; x: number; y: number; z: number };
  const faces: WindowFace[] = [];
  const dark = new Color(VOXEL_WINDOW_DARK);
  const teal = new Color(VOXEL_WINDOW_TEAL);
  for (const [xIdx, zIdx, y0dm, y1dm] of payload.buildings) {
    const top = y1dm / 10;
    for (const [dx, dz] of [
      [1, 0],
      [-1, 0],
      [0, 1],
      [0, -1],
    ] as const) {
      const neighbourTop = columnTops.get(columnKey(xIdx + dx, zIdx + dz));
      const faceX = worldXAbs(xIdx) + (dx * cell) / 2 + dx * 0.08;
      const faceZ = worldZAbs(zIdx) + (dz * cell) / 2 + dz * 0.08;
      for (let yCenter = y0dm / 10 + 2; yCenter + 1.2 <= top; yCenter += cell) {
        if (neighbourTop !== undefined && neighbourTop >= yCenter + 1) {
          continue;
        }
        const shine =
          Math.abs(xIdx * 13 + zIdx * 7 + Math.round(yCenter)) % 7 === 0;
        faces.push({
          color: shine ? teal : dark,
          nx: dx,
          nz: dz,
          x: faceX,
          y: yCenter,
          z: faceZ,
        });
      }
    }
  }
  if (faces.length > 0) {
    const panes = new InstancedMesh(
      new PlaneGeometry(1, 1),
      new MeshBasicMaterial({ color: 0xffffff, side: DoubleSide }),
      faces.length,
    );
    panes.name = "Voxel facade windows";
    const matrix = new Matrix4();
    faces.forEach((face, index) => {
      // Plane spans the face's tangent; dir = up × normal in the plane.
      const dirX = -face.nz;
      const dirZ = face.nx;
      matrix.set(
        dirX * 2.1, 0, face.nx, face.x,
        0, 2.3, 0, face.y,
        dirZ * 2.1, 0, face.nz, face.z,
        0, 0, 0, 1,
      );
      panes.setMatrixAt(index, matrix);
      panes.setColorAt(index, face.color);
    });
    panes.instanceMatrix.needsUpdate = true;
    if (panes.instanceColor) {
      panes.instanceColor.needsUpdate = true;
    }
    panes.frustumCulled = false;
    group.add(panes);
  }

  const trunks = instancedBoxes("Voxel tree trunks", payload.trees.length);
  const crowns = instancedBoxes("Voxel tree crowns", payload.trees.length * 2);
  for (const [xIdx, zIdx, y0dm, hdm] of payload.trees) {
    const y0 = y0dm / 10;
    const height = Math.max(cell, hdm / 10);
    const trunkHeight = Math.max(cell / 2, height - cell * 1.5);
    const species = Math.abs(xIdx * 7 + zIdx * 13) % 5;
    center.set(worldXAbs(xIdx), y0 + trunkHeight / 2, worldZAbs(zIdx));
    size.set(cell * 0.45, trunkHeight, cell * 0.45);
    // Every fifth tree is a birch (pale trunk), like a mixed park.
    trunks.write(
      center,
      size,
      species === 0
        ? new Color(0xd6dfe0)
        : shadeFor(TRUNK_SHADES, xIdx, zIdx, 1),
    );
    const crownHeight = cell * 1.9;
    center.set(
      worldXAbs(xIdx),
      y0 + trunkHeight + crownHeight / 2,
      worldZAbs(zIdx),
    );
    size.set(cell * 2.2, crownHeight, cell * 2.2);
    crowns.write(center, size, shadeFor(LEAF_SHADES, xIdx, zIdx, 2));
    // Every third tree stacks a smaller crown — the spruce silhouette.
    if (species === 1 || species === 3) {
      center.set(
        worldXAbs(xIdx),
        y0 + trunkHeight + crownHeight + cell * 0.55,
        worldZAbs(zIdx),
      );
      size.set(cell * 1.3, cell * 1.1, cell * 1.3);
      crowns.write(center, size, shadeFor(LEAF_SHADES, xIdx, zIdx, 3));
    }
  }
  group.add(trunks.mesh);
  group.add(crowns.mesh);

  // Meadow flowers: sparse deterministic colour dots on grass runs —
  // the small-scale life real Minecraft plains have.
  const FLOWER_TONES = [0xe6bd4c, 0xe79a61, 0xf7fbf7] as const;
  const grassClass = payload.classes.indexOf("grass");
  const groundTopY = groundTopSampler(payload);
  const flowerSpots: Array<[number, number, number]> = [];
  payload.ground_rows.forEach((row, zOffset) => {
    for (const [xStart, run, classId] of row) {
      if (classId !== grassClass) {
        continue;
      }
      for (let step = 0; step < run; step += 1) {
        const xOffset = xStart + step;
        const roll = Math.abs(xOffset * 2654435761 + zOffset * 40503) % 41;
        if (roll === 0) {
          flowerSpots.push([xOffset, zOffset, roll]);
        }
      }
    }
  });
  const flowers = instancedBoxes("Voxel meadow flowers", flowerSpots.length);
  for (const [xOffset, zOffset] of flowerSpots) {
    const topY = groundTopY(xOffset, zOffset);
    center.set(
      worldXAbs(payload.grid.min_x_idx + xOffset),
      topY + 0.3,
      worldZAbs(payload.grid.min_z_idx + zOffset),
    );
    size.set(0.55, 0.6, 0.55);
    flowers.write(
      center,
      size,
      new Color(
        FLOWER_TONES[Math.abs(xOffset * 31 + zOffset * 17) % FLOWER_TONES.length],
      ),
    );
  }
  group.add(flowers.mesh);

  for (const child of group.children) {
    if (child instanceof InstancedMesh) {
      child.instanceMatrix.needsUpdate = true;
      if (child.instanceColor) {
        child.instanceColor.needsUpdate = true;
      }
      child.frustumCulled = false;
    }
  }
  return group;
}
